import React, { useState } from 'react';
import { motion } from 'framer-motion';
import './QuizSetup.css';
import { FaChalkboardTeacher, FaUserGraduate, FaUserTie } from 'react-icons/fa';

const roles = [
  { label: 'Teacher', value: 'teacher' },
  { label: 'Mentor', value: 'mentor' },
  { label: 'Student', value: 'student' },
];
const difficulties = [
  { label: 'Easy', value: 'easy' },
  { label: 'Medium', value: 'medium' },
  { label: 'Hard', value: 'hard' },
];

function QuizSetup({ onGenerate }) {
  const [prompt, setPrompt] = useState('');
  const [role, setRole] = useState('teacher');
  const [difficulty, setDifficulty] = useState('easy');

  const icons = {
    teacher: <FaChalkboardTeacher color="#6366f1" size={24} />, 
    mentor: <FaUserTie color="#22c55e" size={24} />, 
    student: <FaUserGraduate color="#f59e42" size={24} />
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (prompt.trim()) {
      onGenerate({ prompt, role, difficulty });
    }
  };

  return (
    <motion.form 
      className="quiz-setup vibrant"
      onSubmit={handleSubmit}
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.7 }}
    >
      <h2>
        {icons[role]} Create Your AI Quiz
      </h2>
      <label>
        Quiz Topic or Prompt
        <input
          type="text"
          placeholder="e.g. Photosynthesis, Python Basics..."
          value={prompt}
          onChange={e => setPrompt(e.target.value)}
          required
        />
      </label>
      <div className="selectors">
        <div>
          <span>Role:</span>
          <select value={role} onChange={e => setRole(e.target.value)}>
            {roles.map(r => (
              <option key={r.value} value={r.value}>{r.label}</option>
            ))}
          </select>
        </div>
        <div>
          <span>Difficulty:</span>
          <select value={difficulty} onChange={e => setDifficulty(e.target.value)}>
            {difficulties.map(d => (
              <option key={d.value} value={d.value}>{d.label}</option>
            ))}
          </select>
        </div>
      </div>
      <button type="submit" className="vibrant-btn">✨ Generate Quiz</button>
    </motion.form>
  );
}

export default QuizSetup;
